import React, { useState } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, sprite: '/sprites/knight - Copy.PNG', move: 2 },
  { name: 'Archer', hp: 80, atk: 25, sprite: '/sprites/archer (2).PNG', move: 3 },
  { name: 'Mage', hp: 70, atk: 40, sprite: '/sprites/Mage - Copy.PNG', move: 2 },
  { name: 'Healer', hp: 90, atk: 10, sprite: '/sprites/healer - Copy.PNG', move: 2 },
  { name: 'Warrior', hp: 110, atk: 35, sprite: '/sprites/warrior - Copy.PNG', move: 1 },
  { name: 'Rogue', hp: 75, atk: 30, sprite: '/sprites/rogue - Copy.PNG', move: 4 },
  { name: 'Summoner', hp: 65, atk: 45, sprite: '/sprites/summoner - Copy.PNG', move: 2 },
  { name: 'Paladin', hp: 95, atk: 20, sprite: '/sprites/paladin - Copy.PNG', move: 1 },
];

const generateTeam = (team, row) => {
  let idCounter = team === 'A' ? 1 : 100; // Ensures unique IDs
  return baseCharacters.map((c, i) => ({
    ...c,
    id: idCounter + i,
    x: i,
    y: row,
    team,
    movesLeft: c.move,
    hasAttacked: false,
  }));
};

const getInitialCharacters = () => [
  ...generateTeam('A', 0),
  ...generateTeam('B', gridSize - 1),
];

function App() {
  const [characters, setCharacters] = useState(getInitialCharacters());
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');
  const [winner, setWinner] = useState(null);

  const selectedChar = characters.find((c) => c.id === selectedId && c.hp > 0);

  const checkWinner = (updatedChars) => {
    const teamAAlive = updatedChars.some((c) => c.team === 'A' && c.hp > 0);
    const teamBAlive = updatedChars.some((c) => c.team === 'B' && c.hp > 0);
    if (!teamAAlive) setWinner('Team B');
    else if (!teamBAlive) setWinner('Team A');
  };

  const moveCharacter = (id, dx, dy) => {
    if (winner) return;
    setCharacters((prev) => {
      const updated = prev.map((c) => {
        if (c.id === id && c.team === turn && c.hp > 0) {
          if (c.movesLeft <= 0) return c;
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          const occupied = prev.some(
            (o) => o.x === newX && o.y === newY && o.hp > 0
          );
          if (occupied) return c;
          return { ...c, x: newX, y: newY, movesLeft: c.movesLeft - 1 };
        }
        return c;
      });
      checkWinner(updated);
      return updated;
    });
  };

  const attack = (attackerId) => {
    if (winner) return;
    const attacker = characters.find((c) => c.id === attackerId);
    if (!attacker || attacker.hasAttacked || attacker.hp <= 0) return;

    const targets = characters.filter(
      (c) =>
        c.team !== attacker.team &&
        c.hp > 0 &&
        Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1
    );
    if (targets.length > 0) {
      const target = targets[0];
      setCharacters((prev) => {
        const updated = prev.map((c) => {
          if (c.id === target.id) {
            return { ...c, hp: Math.max(0, c.hp - attacker.atk) };
          } else if (c.id === attackerId) {
            return { ...c, hasAttacked: true };
          }
          return c;
        });
        checkWinner(updated);
        return updated;
      });
    }
  };

  const endTurn = () => {
    if (winner) return;
    setSelectedId(null);
    setCharacters((prev) =>
      prev.map((c) =>
        c.team !== turn
          ? { ...c, movesLeft: c.move, hasAttacked: false }
          : c
      )
    );
    setTurn((prev) => (prev === 'A' ? 'B' : 'A'));
  };

  const restartGame = () => {
    setCharacters(getInitialCharacters());
    setTurn('A');
    setSelectedId(null);
    setWinner(null);
  };

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      {winner ? (
        <h2>{winner} Wins!</h2>
      ) : (
        <h2>Turn: Team {turn}</h2>
      )}
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find((c) => c.x === x && c.y === y && c.hp > 0);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''}`}
                  onClick={() => {
                    if (char && char.team === turn && char.hp > 0) setSelectedId(char.id);
                  }}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                      <div className="stats-box">
                        <div>{char.name}</div>
                        <div>HP: {char.hp}</div>
                        <div>Moves: {char.movesLeft}</div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <div className="controls">
        {selectedChar && selectedChar.team === turn && !winner && (
          <>
            <button onClick={() => moveCharacter(selectedId, -1, 0)}>←</button>
            <button onClick={() => moveCharacter(selectedId, 1, 0)}>→</button>
            <button onClick={() => moveCharacter(selectedId, 0, -1)}>↑</button>
            <button onClick={() => moveCharacter(selectedId, 0, 1)}>↓</button>
            <button
              onClick={() => attack(selectedId)}
              disabled={selectedChar.hasAttacked}
            >
              Attack
            </button>
            <button onClick={endTurn}>End Turn</button>
          </>
        )}
        <button onClick={restartGame}>Restart Game</button>
      </div>
    </div>
  );
}

export default App;
